CREATE ALGORITHM=UNDEFINED DEFINER=`neolab`@`%` SQL SECURITY DEFINER VIEW `v_stock_semaforo_ui` AS select `p`.`sku` AS `sku`,coalesce(convert(nullif(`tp`.`Item Description`,'') using utf8mb4),nullif(`tp`.`Descripcion_Completa`,''),convert(`p`.`sku` using utf8mb4)) AS `producto`,cast((coalesce(`se`.`Stock_Fisico_Libre`,0) + coalesce(`se`.`Impo_Libre`,0)) as decimal(18,2)) AS `stock_actual`,cast(coalesce(`p`.`stock_min`,0) as decimal(18,2)) AS `stock_min`,cast(coalesce(`p`.`stock_objetivo`,0) as decimal(18,2)) AS `stock_objetivo`,(case when ((coalesce(`se`.`Stock_Fisico_Libre`,0) + coalesce(`se`.`Impo_Libre`,0)) <= coalesce(`p`.`stock_min`,0)) then 'QUIEBRE' when ((coalesce(`se`.`Stock_Fisico_Libre`,0) + coalesce(`se`.`Impo_Libre`,0)) >= (coalesce(`p`.`stock_objetivo`,0) * 1.35)) then 'SOBRESTOCK' else 'OK' end) AS `estado`,cast(coalesce(`se`.`Stock_Fisico_Libre`,0) as decimal(18,2)) AS `stock_fisico`,cast(coalesce(`se`.`Impo_Libre`,0) as decimal(18,2)) AS `impo_libre`,cast(coalesce(`se`.`Reservado_Total`,0) as decimal(18,2)) AS `reservado`,`se`.`UltimoRegistro` AS `ultimo_registro` from ((`parametros_sku` `p` left join `v_stock_estado` `se` on((trim(`se`.`SKU`) = trim(`p`.`sku`)))) left join `tablaprecios` `tp` on((trim(`tp`.`Product Number`) = trim(`p`.`sku`)))) where ((coalesce(`p`.`activo`,1) = 1) and ((`tp`.`Product Number` is not null) or (`se`.`SKU` is not null)))